import React from "react";
import "./CourseList.css";

const coursesData = [
    "DevOps", "Cloud Computing", "Python Programming",
    "Java Programming", "Linux Administration", "Databases",
    "Tableau", "C & C++", "Networking",
    "Windows Administration", "PowerBI", "Artificial Intelligence",
    "Bash Scripting"
];

const CourseList = () => {
    return (
        <section id="featured-courses-section" className="section-padding">
            <div className="container">
                <div className="section-header text-center">
                    <h2>Featured Courses</h2>
                    <p>Explore a variety of courses designed to enhance your skills and career opportunities.</p>
                </div>

                <div className="courses-grid">
                    {coursesData.map((course, index) => (
                        <div key={index} className="course-card glass-card">
                            <div className="course-icon">
                                {/* Placeholder icon */}
                                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                                    <path d="M12 2L2 7L12 12L22 7L12 2Z" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                                    <path d="M2 17L12 22L22 17" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                                    <path d="M2 12L12 17L22 12" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                                </svg>
                            </div>
                            <h3>{course}</h3>
                        </div>
                    ))}
                </div>
            </div>
        </section>
    );
};

export default CourseList;
